import { mkdir, readFile, rename, rm, writeFile } from "node:fs/promises";
import { dirname } from "node:path";
export async function readInstructionFile(filePath) {
    try {
        return { text: await readFile(filePath, "utf8"), exists: true };
    }
    catch (error) {
        if (error.code === "ENOENT") {
            return { text: "", exists: false };
        }
        throw error;
    }
}
export async function writeInstructionFile(filePath, text) {
    const existing = await readInstructionFile(filePath);
    let backupPath;
    if (existing.exists) {
        backupPath = `${filePath}.bak`;
        await writeFile(backupPath, existing.text, "utf8");
    }
    await mkdir(dirname(filePath), { recursive: true });
    const tempPath = `${filePath}.tmp`;
    await writeFile(tempPath, text, "utf8");
    await rename(tempPath, filePath);
    return {
        filePath,
        ...(backupPath ? { backupPath } : {}),
    };
}
export async function removeInstructionFile(filePath) {
    const existing = await readInstructionFile(filePath);
    if (existing.exists) {
        await rm(filePath, { force: true });
    }
    return { filePath, removed: existing.exists };
}
export function collectGuidanceIssues(text, options) {
    const issues = [];
    for (const check of options.required) {
        if (!text.includes(check.requiredText)) {
            issues.push(check.missingIssue);
        }
    }
    for (const check of options.forbidden ?? []) {
        if (text.includes(check.forbiddenText)) {
            issues.push(check.presentIssue);
        }
    }
    return issues;
}
